@namespace Lumeo

@* Inline SVGs sized to the checkbox's 12-unit viewBox. Stroke-width ~2.75 gives a crisper check
   than Lucide's default 2 at this size, and `stroke-linecap/join="round"` kills the pixel-corner
   sharpness the user was seeing. *@

@* Render the label, control and helper/error as ONE self-contained vertical block so the
   field never splays into a row when dropped in a flex / centered container. Standalone
   form-field structural fix. *@
<div class="flex flex-col items-start">
@if (Label is not null)
{
    <div class="flex items-start gap-2.5">
        <button type="button" id="@EffectiveId" role="checkbox" aria-checked="@AriaChecked"
                aria-required="@Required.ToString().ToLowerInvariant()"
                aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
                aria-describedby="@DescribedBy"
                data-state="@DataState" data-disabled="@(Disabled ? string.Empty : null)"
                class="@CssClass" @onclick="Toggle" disabled="@Disabled" @attributes="EffectiveAttributes">
            @RenderIcon()
        </button>
        <div class="grid gap-1 leading-none pt-[1px]">
            <label for="@EffectiveId" class="text-sm font-medium leading-none cursor-pointer peer-disabled:cursor-not-allowed peer-disabled:opacity-70">
                @Label
                @if (Required)
                {
                    <span class="text-destructive ms-0.5">*</span>
                }
            </label>
            @if (!string.IsNullOrEmpty(Description))
            {
                <p id="@_descriptionId" class="text-xs text-muted-foreground">@Description</p>
            }
        </div>
    </div>
}
else
{
    <button type="button" id="@EffectiveId" role="checkbox" aria-checked="@AriaChecked" aria-label="@AriaLabel"
            aria-required="@Required.ToString().ToLowerInvariant()"
            aria-invalid="@EffectiveInvalid.ToString().ToLowerInvariant()"
            aria-describedby="@DescribedBy"
            data-state="@DataState" data-disabled="@(Disabled ? string.Empty : null)"
            class="@CssClass" @onclick="Toggle" disabled="@Disabled" @attributes="EffectiveAttributes">
        @RenderIcon()
    </button>
}

@* Bubble input (Radix pattern): a visually-hidden, non-focusable native checkbox
   that mirrors the checked state and carries Name/Value so the control participates
   in a plain <form> POST. Rendered when a Name is set directly OR inherited from a
   composing <FormField Name="..."> (EffectiveName). Indeterminate posts as unchecked
   (native semantics). aria-hidden + tabindex=-1 keep it out of the a11y tree and tab
   order — the role="checkbox" <button> above owns interaction. *@
@if (!string.IsNullOrEmpty(EffectiveName))
{
    <input type="checkbox" aria-hidden="true" tabindex="-1"
           name="@EffectiveName" value="@EffectiveValue"
           checked="@(Checked && !IsIndeterminate)"
           disabled="@Disabled" required="@Required"
           class="pointer-events-none absolute h-4 w-4 -translate-x-full opacity-0"
           style="clip: rect(0 0 0 0); clip-path: inset(50%); overflow: hidden; white-space: nowrap;" />
}

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}
</div>

@code {
    private RenderFragment RenderIcon() => __builder =>
    {
        if (IsIndeterminate)
        {
            <svg class="pointer-events-none h-2.5 w-2.5" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="2.75" stroke-linecap="round">
                <line x1="3" y1="6" x2="9" y2="6" />
            </svg>
        }
        else if (Checked)
        {
            <svg class="pointer-events-none h-2.5 w-2.5" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="2.75" stroke-linecap="round" stroke-linejoin="round">
                <polyline points="2.5,6.5 5,8.5 9.5,3.5" />
            </svg>
        }
    };
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    /// <summary>Whether the checkbox is checked. Pair with <see cref="CheckedChanged"/> for two-way binding. Ignored visually while <see cref="IsIndeterminate"/> is true.</summary>
    [Parameter] public bool Checked { get; set; }

    /// <summary>Raised when the user toggles the checkbox.</summary>
    [Parameter] public EventCallback<bool> CheckedChanged { get; set; }

    /// <summary>Renders the dash ("mixed") visual instead of check/empty. Clicking clears it and checks the box. Pair with <see cref="IsIndeterminateChanged"/> for two-way binding.</summary>
    [Parameter] public bool IsIndeterminate { get; set; }

    /// <summary>Raised when <see cref="IsIndeterminate"/> is cleared by a user click.</summary>
    [Parameter] public EventCallback<bool> IsIndeterminateChanged { get; set; }

    /// <summary>Disables interaction and dims the checkbox.</summary>
    [Parameter] public bool Disabled { get; set; }

    /// <summary>Visible label text rendered next to the checkbox. When unset, use <see cref="AriaLabel"/> instead so the control still has an accessible name.</summary>
    [Parameter] public string? Label { get; set; }

    /// <summary>Optional helper text rendered under <see cref="Label"/>, wired to the control via <c>aria-describedby</c>.</summary>
    [Parameter] public string? Description { get; set; }

    /// <summary>Explicit element id for the checkbox button. When inside a <see cref="FormField"/>, the field's generated control id takes precedence. Falls back to an auto-generated id.</summary>
    [Parameter] public string? Id { get; set; }
    /// <summary>
    /// Accessible name used when <see cref="Label"/> is not set (the checkbox
    /// renders without a visible label). Required for WCAG compliance when
    /// the checkbox sits alone in a cell or alongside text that isn't linked
    /// to it via <c>for</c> / <c>htmlFor</c>.
    /// </summary>
    [Parameter] public string? AriaLabel { get; set; }

    /// <summary>
    /// When true, the checkmark draws itself in via stroke-dasharray and the
    /// box plays a subtle 200ms scale bounce on check. Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool Animated { get; set; }

    /// <summary>
    /// When true, triggers a short haptic vibration via <c>navigator.vibrate()</c>
    /// each time the checkbox state changes. Silently no-ops on browsers without the
    /// Vibration API (e.g. iOS Safari). Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool HapticFeedback { get; set; }

    [Inject] private HapticsService Haptics { get; set; } = default!;

    /// <summary>Marks the field as required: sets <c>aria-required</c> and renders a destructive-colored asterisk after <see cref="Label"/>.</summary>
    [Parameter] public bool Required { get; set; }

    /// <summary>Forces the invalid/error visual and <c>aria-invalid</c>, independent of any cascaded <see cref="FormField"/> error state.</summary>
    [Parameter] public bool Invalid { get; set; }

    /// <summary>Error message shown below the control when invalid and not composed inside a <see cref="FormField"/> (which owns its own error display).</summary>
    [Parameter] public string? ErrorText { get; set; }

    /// <summary>Helper text shown below the control when not invalid and not composed inside a <see cref="FormField"/>.</summary>
    [Parameter] public string? HelperText { get; set; }

    /// <summary>Field name for the hidden native bubble input, so the checkbox participates in a plain <c>&lt;form&gt;</c> POST. Falls back to the cascaded <see cref="FormField"/>'s name when unset.</summary>
    [Parameter] public string? Name { get; set; }

    /// <summary>
    /// Value submitted for this checkbox in a native <c>&lt;form&gt;</c> POST when
    /// <see cref="Name"/> is set and the box is checked. Mirrors the native
    /// checkbox default of <c>"on"</c>.
    /// </summary>
    [Parameter] public string? Value { get; set; }

    private string EffectiveValue => Value ?? "on";

    // Field name for the bubble input: a direct Name wins, else the name cascaded by a
    // composing <FormField Name="...">. Lets `<FormField Name="x"><Checkbox/></FormField>`
    // post the checkbox value without repeating the name on the Checkbox (Codex round-3 P2).
    private string? EffectiveName => string.IsNullOrEmpty(Name) ? FormField?.Name : Name;

    /// <summary>Additional CSS classes merged onto the checkbox button element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Unmatched attributes are splatted onto the checkbox button element (an explicit <c>id</c> is ignored when inside a <see cref="FormField"/>).</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    // Point aria-describedby at the FormField's help/error text (null outside a field).
    private string? FormFieldDescribedBy => FormField?.DescribedBy;

    // Only the random fallback is cached (it must stay stable across renders).
    // The effective id is derived per render so that a runtime change to the Id
    // parameter (or the cascaded FormField.ControlId) flows through to BOTH the
    // <button id> and the <label for> instead of latching to the first-render value.
    private readonly string _generatedId = LumeoIds.New("checkbox");

    // Inside a FormField the generated ControlId must own the <button> id so the
    // FormField's <Label For> always resolves to this button (Codex P2). A
    // consumer-splatted id in AdditionalAttributes is therefore ignored in that
    // context (and stripped from EffectiveAttributes below). Outside a FormField a
    // splatted id wins via LumeoIds.Effective, which keeps the component's own
    // <label for> in sync with whatever id actually lands on the button (Triage #23).
    private string EffectiveId => InsideFormField
        ? ((string.IsNullOrEmpty(FormField?.ControlId) ? null : FormField!.ControlId) ?? Id ?? _generatedId)
        : LumeoIds.Effective(AdditionalAttributes, Id ?? _generatedId);

    // Inside a FormField the generated id (EffectiveId above) must win on the
    // <button>. Strip a consumer-splatted id from the attribute bag so it cannot
    // override the explicit id= that renders before @attributes. Outside a FormField
    // the bag passes through unchanged.
    private Dictionary<string, object>? EffectiveAttributes =>
        InsideFormField && AdditionalAttributes?.ContainsKey("id") == true
            ? AdditionalAttributes.Where(kv => kv.Key != "id").ToDictionary(kv => kv.Key, kv => kv.Value)
            : AdditionalAttributes;

    // Stable id for the standalone Description <p> so it can be referenced by
    // aria-describedby (only meaningful/rendered when Description is non-empty).
    private readonly string _descriptionId = LumeoIds.New("checkbox-desc");

    // aria-describedby points at the FormField's help/error text (inside a field) AND,
    // when a standalone Description is shown, that description's <p>. Null/empty parts
    // are dropped; an empty result renders as no attribute at all (not aria-describedby="").
    private string? DescribedBy
    {
        get
        {
            var joined = Cx.Join(
                FormFieldDescribedBy,
                string.IsNullOrEmpty(Description) ? null : _descriptionId);
            return string.IsNullOrEmpty(joined) ? null : joined;
        }
    }

    private string AriaChecked => IsIndeterminate ? "mixed" : Checked.ToString().ToLower();

    // shadcn/Radix data-state styling hook: consumers can target
    // data-[state=checked] / data-[state=indeterminate] in CSS.
    private string DataState => IsIndeterminate ? "indeterminate" : (Checked ? "checked" : "unchecked");

    private string CssClass => Cx.Merge(
        "peer inline-flex items-center justify-center h-4 w-4 shrink-0 cursor-pointer rounded transition-colors duration-150 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50",
        EffectiveInvalid
            ? (Checked || IsIndeterminate ? "bg-destructive border border-destructive text-primary-foreground focus-visible:ring-destructive/50" : "border border-destructive focus-visible:ring-destructive/50")
            : (Checked || IsIndeterminate ? "bg-primary border border-primary text-primary-foreground focus-visible:ring-ring" : "border border-primary/60 bg-background hover:border-primary focus-visible:ring-ring"),
        Cx.When(Animated && Checked, "lumeo-checkbox-animated"),
        Class);

    private async Task Toggle()
    {
        if (!Disabled)
        {
            if (IsIndeterminate)
            {
                IsIndeterminate = false;
                await IsIndeterminateChanged.InvokeAsync(false);
                Checked = true;
                await CheckedChanged.InvokeAsync(true);
            }
            else
            {
                Checked = !Checked;
                await CheckedChanged.InvokeAsync(Checked);
            }
            if (HapticFeedback) await Haptics.Light();
        }
    }
}
